var sortSentence = function(s) {
    const tokens = s.split(' ');
    const res = new Array(tokens.length);
    for (const t of tokens) {
        const pos = Number(t[t.length - 1]);
        res[pos - 1] = t.slice(0, -1);
    }
    return res.join(' ');
};
